__CPROVER_requires(__CPROVER_is_fresh(s, sizeof(*s)))
__CPROVER_requires(blockstart <= blockend)
__CPROVER_requires(blockend - blockstart <= 100)
__CPROVER_assigns(s->options, s->blockstart, s->blockend, s->lmc)

